/* Test driver */
public class Main {
    public static void main(String[] args) {
        Booking.resetCounter();
        AirlineSystem a = new AirlineSystem();
        Flight f = new Flight("F1", "NYC", "LAX", 100.00);
        f.addSeats(1, 0, 0);
        a.addFlight(f);
        Booking b = a.book(new Passenger("A", ""), f, "ECONOMY");
        a.cancel(b);
        if (f.getAvailable("ECONOMY") == 1) System.out.println("CANCEL_OK");
        Booking b2 = a.book(new Passenger("B", ""), f, "ECONOMY");
        if (b2 != null) System.out.println("REBOOK_OK");
    }
}

